"use client"

import { useState, useTransition, Suspense } from "react"
import { useSearchParams } from "next/navigation"
import { completeOnboarding } from "@/app/actions/auth"
import { Compass, Users, Truck, UserCheck, RefreshCw, AlertCircle, Building2, UploadCloud, FileCheck } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Logo } from "@/components/ui/logo"

type Role = "commercant" | "transitaire" | "transporteur" | "chauffeur"

function RegisterForm() {
  const searchParams = useSearchParams()
  const [phone, setPhone] = useState(searchParams.get("phone") || "")
  const [role, setRole] = useState<Role>("commercant")
  const [fullName, setFullName] = useState("")
  const [companyName, setCompanyName] = useState("")
  const [rccm, setRccm] = useState("")
  const [nif, setNif] = useState("")
  const [agrementDouane, setAgrementDouane] = useState("")
  
  const [error, setError] = useState<string | null>(null)
  const [isPending, startTransition] = useTransition()

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)

    if (!phone) {
      setError("Veuillez renseigner votre numéro de téléphone (Obligatoire pour l'authentification SMS)")
      return
    }

    if (!fullName) {
      setError("Veuillez renseigner votre nom complet")
      return
    }

    if (["transitaire", "transporteur"].includes(role)) {
      if (!companyName) return setError("Veuillez renseigner le nom de votre entreprise")
      if (!rccm) return setError("Le N° RCCM est strictement obligatoire pour les professionnels")
      if (!nif) return setError("Le N° NIF est strictement obligatoire pour les professionnels")
    }

    if (role === "transitaire" && !agrementDouane) {
      return setError("L'Agrément en Douane est exigé pour valider votre statut de transitaire")
    }

    startTransition(async () => {
      const res = await completeOnboarding({
        phone,
        role,
        fullName,
        companyName: ["transitaire", "transporteur"].includes(role) ? companyName : undefined,
        rccm: ["transitaire", "transporteur"].includes(role) ? rccm : undefined,
        nif: ["transitaire", "transporteur"].includes(role) ? nif : undefined,
        agrementDouane: role === "transitaire" ? agrementDouane : undefined,
      })

      if (res?.error) {
        setError(res.error)
      }
    })
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 py-12 px-4 font-sans">
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
        <div className="bg-slate-900 p-8 text-center flex flex-col items-center">
          <Logo className="h-24 mb-6" />
          <h1 className="text-2xl font-bold text-white">Finalisez votre inscription</h1>
          <p className="text-slate-400 mt-2 text-sm">Créez votre profil professionnel DoniCargo</p>
        </div>
        
        <form onSubmit={handleSubmit} className="p-8 space-y-8">
          {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-xl text-xs font-semibold flex items-start gap-2.5 border border-red-100 animate-shake">
              <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          )}

          {/* 1. Profile information */}
          <div className="space-y-4">
            <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider">1. Informations Personnelles</h3>
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-500 mb-2">Numéro de téléphone *</label>
                <input
                  type="tel"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  placeholder="Ex: +223 70 00 00 00"
                  className="block w-full border border-slate-200 bg-white text-slate-800 rounded-lg py-3 px-4 text-sm focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all"
                />
              </div>
              <div>
                <label htmlFor="fullName" className="block text-xs font-semibold text-slate-500 mb-2">Nom complet</label>
                <input
                  type="text"
                  id="fullName"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  placeholder="Ex: Amadou Diallo"
                  className="block w-full border border-slate-200 rounded-lg py-3 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all"
                />
              </div>
            </div>
          </div>

          {/* 2. Role Selector */}
          <div className="space-y-4">
            <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider">2. Choisissez votre rôle</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              
              {/* Commerçant */}
              <div 
                onClick={() => setRole("commercant")}
                className={`cursor-pointer border-2 rounded-xl p-4 text-center transition-all ${
                  role === "commercant" 
                    ? "border-orange-500 bg-orange-50/20" 
                    : "border-slate-100 hover:border-slate-200"
                }`}
              >
                <Compass className={`w-8 h-8 mx-auto mb-2 ${role === "commercant" ? "text-orange-600" : "text-slate-400"}`} />
                <h4 className="font-bold text-slate-800 text-xs">Commerçant</h4>
                <p className="text-[10px] text-slate-400 mt-1">Import/Export</p>
              </div>

              {/* Transitaire */}
              <div 
                onClick={() => setRole("transitaire")}
                className={`cursor-pointer border-2 rounded-xl p-4 text-center transition-all ${
                  role === "transitaire" 
                    ? "border-orange-500 bg-orange-50/20" 
                    : "border-slate-100 hover:border-slate-200"
                }`}
              >
                <Building2 className={`w-8 h-8 mx-auto mb-2 ${role === "transitaire" ? "text-orange-600" : "text-slate-400"}`} />
                <h4 className="font-bold text-slate-800 text-xs">Transitaire</h4>
                <p className="text-[10px] text-slate-400 mt-1">Douane & Port</p>
              </div>

              {/* Transporteur */}
              <div 
                onClick={() => setRole("transporteur")}
                className={`cursor-pointer border-2 rounded-xl p-4 text-center transition-all ${
                  role === "transporteur" 
                    ? "border-orange-500 bg-orange-50/20" 
                    : "border-slate-100 hover:border-slate-200"
                }`}
              >
                <Truck className={`w-8 h-8 mx-auto mb-2 ${role === "transporteur" ? "text-orange-600" : "text-slate-400"}`} />
                <h4 className="font-bold text-slate-800 text-xs">Transporteur</h4>
                <p className="text-[10px] text-slate-400 mt-1">Propriétaire flotte</p>
              </div>

              {/* Chauffeur */}
              <div 
                onClick={() => setRole("chauffeur")}
                className={`cursor-pointer border-2 rounded-xl p-4 text-center transition-all ${
                  role === "chauffeur" 
                    ? "border-orange-500 bg-orange-50/20" 
                    : "border-slate-100 hover:border-slate-200"
                }`}
              >
                <Users className={`w-8 h-8 mx-auto mb-2 ${role === "chauffeur" ? "text-orange-600" : "text-slate-400"}`} />
                <h4 className="font-bold text-slate-800 text-xs">Chauffeur</h4>
                <p className="text-[10px] text-slate-400 mt-1">Conducteur camion</p>
              </div>

            </div>
          </div>

          {/* 3. Professional details (conditional) */}
          {["transitaire", "transporteur"].includes(role) && (
            <div className="space-y-4 border-t border-slate-100 pt-6 animate-fadeIn">
              <div className="flex items-center gap-2">
                <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider">3. Identité Professionnelle (KYB)</h3>
                <Badge variant="secondary" className="bg-blue-50 text-blue-700 border-blue-100 text-[10px]">Vérification Stricte</Badge>
              </div>
              <div className="grid md:grid-cols-3 gap-4">
                <div className="md:col-span-1">
                  <label htmlFor="companyName" className="block text-xs font-semibold text-slate-500 mb-2">Nom de l'entreprise *</label>
                  <input
                    type="text"
                    id="companyName"
                    value={companyName}
                    onChange={(e) => setCompanyName(e.target.value)}
                    placeholder="Ex: Transit Express Mali"
                    className="block w-full border border-slate-200 rounded-lg py-3 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all"
                  />
                </div>
                <div>
                  <label htmlFor="rccm" className="block text-xs font-semibold text-slate-500 mb-2">N° RCCM *</label>
                  <input
                    type="text"
                    id="rccm"
                    value={rccm}
                    onChange={(e) => setRccm(e.target.value)}
                    placeholder="Ex: MA-BKO-2026-B..."
                    className="block w-full border border-slate-200 rounded-lg py-3 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all"
                  />
                </div>
                <div>
                  <label htmlFor="nif" className="block text-xs font-semibold text-slate-500 mb-2">N° NIF *</label>
                  <input
                    type="text"
                    id="nif"
                    value={nif}
                    onChange={(e) => setNif(e.target.value)}
                    placeholder="Ex: 082019208..."
                    className="block w-full border border-slate-200 rounded-lg py-3 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all"
                  />
                </div>
              </div>
              
              {role === "transitaire" && (
                <div className="mt-4 p-5 bg-orange-50/50 border border-orange-100 rounded-xl space-y-4">
                  <div className="flex items-start gap-3">
                    <div className="w-10 h-10 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center shrink-0">
                      <FileCheck className="w-5 h-5" />
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-slate-800">Agrément en Douane Obligatoire</h4>
                      <p className="text-xs text-slate-500 mt-1">Conformément aux directives douanières, les transitaires doivent justifier de leur agrément pour opérer sur la plateforme.</p>
                    </div>
                  </div>
                  
                  <div className="grid md:grid-cols-2 gap-4">
                    <div>
                      <label htmlFor="agrementDouane" className="block text-xs font-semibold text-slate-500 mb-2">N° d'Agrément en Douane *</label>
                      <input
                        type="text"
                        id="agrementDouane"
                        value={agrementDouane}
                        onChange={(e) => setAgrementDouane(e.target.value)}
                        placeholder="Ex: 0045/DGD/2026"
                        className="block w-full border border-slate-200 rounded-lg py-3 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all bg-white"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-2">Copie de l'Agrément (PDF/Image) *</label>
                      <button type="button" className="w-full flex items-center justify-center gap-2 border-2 border-dashed border-slate-300 hover:border-orange-500 hover:bg-orange-50 hover:text-orange-600 text-slate-500 rounded-lg py-2.5 px-4 text-sm transition-all">
                        <UploadCloud className="w-4 h-4" />
                        Uploader le document
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Submit button */}
          <button
            type="submit"
            disabled={isPending}
            className="w-full flex justify-center items-center gap-2 py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-semibold text-white bg-orange-600 hover:bg-orange-700 disabled:opacity-50 transition-all"
          >
            {isPending ? (
              <RefreshCw className="w-4 h-4 animate-spin" />
            ) : (
              "Créer mon compte professionnel"
            )}
          </button>
        </form>
      </div>
    </div>
  )
}

export default function RegisterPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-slate-500 font-semibold">Chargement du formulaire...</div>
      </div>
    }>
      <RegisterForm />
    </Suspense>
  )
}

"use client"

import { useState, useTransition, Suspense } from "react"
import { useSearchParams } from "next/navigation"
import { verifyOtp } from "@/app/actions/auth"
import { Shield, ArrowRight, RefreshCw, AlertCircle } from "lucide-react"

function VerifyForm() {
  const searchParams = useSearchParams()
  const phone = searchParams.get("phone") || ""
  const isSimulated = searchParams.get("simulated") === "true"

  const [otp, setOtp] = useState("")
  const [error, setError] = useState<string | null>(null)
  const [isPending, startTransition] = useTransition()

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)

    if (otp.length !== 6) {
      setError("Le code doit contenir exactement 6 chiffres")
      return
    }

    startTransition(async () => {
      const res = await verifyOtp(phone, otp)
      if (res?.error) {
        setError(res.error)
      }
    })
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-4 font-sans">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
        <div className="bg-slate-900 p-8 text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-orange-500 mb-4 shadow-lg shadow-orange-500/20">
            <Shield className="w-8 h-8 text-white animate-pulse" />
          </div>
          <h1 className="text-2xl font-bold text-white">Vérification SMS</h1>
          <p className="text-slate-400 mt-2 text-sm">Saisissez le code à 6 chiffres envoyé au</p>
          <p className="text-orange-400 font-semibold text-sm mt-1">{phone || "votre numéro"}</p>
        </div>
        
        <div className="p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="otp" className="block text-sm font-medium text-slate-700 mb-2">
                Code de sécurité (OTP)
              </label>
              <input
                type="text"
                maxLength={6}
                value={otp}
                disabled={isPending}
                onChange={(e) => setOtp(e.target.value.replace(/\D/g, ""))}
                placeholder="------"
                className="block w-full border border-slate-300 rounded-lg py-3.5 px-4 text-slate-900 text-center tracking-[1em] text-xl font-bold focus:ring-orange-500 focus:border-orange-500 outline-none transition-all"
              />
            </div>

            {error && (
              <div className="p-3 bg-red-50 text-red-600 rounded-lg text-xs font-semibold flex items-start gap-2.5 border border-red-100">
                <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
                <span>{error}</span>
              </div>
            )}

            {isSimulated && (
              <div className="p-3 bg-orange-50 text-orange-800 rounded-lg text-xs font-medium border border-orange-100">
                💡 <strong>Mode simulation activé :</strong> Utilisez le code de test <strong>123456</strong> pour poursuivre.
              </div>
            )}

            <button
              type="submit"
              disabled={isPending || otp.length !== 6}
              className="w-full flex justify-center items-center gap-2 py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 disabled:opacity-50 transition-all font-semibold"
            >
              {isPending ? (
                <RefreshCw className="w-4 h-4 animate-spin" />
              ) : (
                "Confirmer le code"
              )}
              {!isPending && <ArrowRight className="w-4 h-4" />}
            </button>
          </form>
          
          <div className="mt-8 text-center border-t border-slate-100 pt-6">
            <p className="text-xs text-slate-500">
              Vous n'avez pas reçu le code ?{' '}
              <button 
                disabled={isPending}
                className="font-medium text-orange-600 hover:text-orange-500 hover:underline"
              >
                Renvoyer par SMS
              </button>
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}

export default function VerifyPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-slate-500 font-semibold">Chargement...</div>
      </div>
    }>
      <VerifyForm />
    </Suspense>
  )
}

"use client"

import { useState, useTransition, useRef } from "react"
import { FileText, UploadCloud, File, Image as ImageIcon, Search, Filter, Download, Trash2, CheckCircle2, RefreshCw } from "lucide-react"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { uploadDocument } from "@/app/actions/upload_document"

function formatBytes(bytes: number) {
  if (bytes === 0) return '0 Bytes'
  const k = 1024
  const sizes = ['Bytes', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
}

export default function DocumentsClient({ initialDocuments }: { initialDocuments: any[] }) {
  const [isDragging, setIsDragging] = useState(false)
  const [isUploading, startUpload] = useTransition()
  const [uploadError, setUploadError] = useState<string | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)
  
  // Utiliser les données de la BD ou les mock data
  const documents = initialDocuments.length > 0 ? initialDocuments : [
    {
      id: "DOC-001",
      name: "Connaissement_MSC_892019.pdf",
      type: "pdf",
      size: "2.4 MB",
      date: "Aujourd'hui, 10:42",
      status: "validé",
      relatedTo: "Lot de Colis Électroniques"
    },
    {
      id: "DOC-002",
      name: "Facture_Proforma_Sogem.pdf",
      type: "pdf",
      size: "1.1 MB",
      date: "Hier, 15:30",
      status: "en_attente",
      relatedTo: "Demande de Devis #QT-1088"
    }
  ]

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(true)
  }

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)
  }

  const processFile = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
      setUploadError("Le fichier dépasse la limite de 10 MB.")
      return
    }
    setUploadError(null)

    const formData = new FormData()
    formData.append("file", file)

    startUpload(async () => {
      const res = await uploadDocument(formData)
      if (res?.error) {
        setUploadError(res.error)
      } else {
        // Succès : le serveur va revalider la route et recharger la liste
        if (fileInputRef.current) {
          fileInputRef.current.value = "" // reset input
        }
      }
    })
  }

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      processFile(e.dataTransfer.files[0])
    }
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      processFile(e.target.files[0])
    }
  }

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b border-slate-200 pb-5">
        <div>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Coffre-fort Numérique</h1>
          <p className="text-sm text-slate-500 mt-1">
            Centralisez et sécurisez tous vos documents logistiques (Factures, Connaissements, Quittances).
          </p>
        </div>
        <button className="bg-slate-900 hover:bg-slate-800 text-white px-4 py-2.5 rounded-xl text-sm font-semibold shadow-sm transition-colors">
          Historique des partages
        </button>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        
        {/* Left Col: Upload Zone & Storage Info */}
        <div className="space-y-6">
          {uploadError && (
            <div className="p-3 bg-red-50 text-red-600 rounded-lg text-xs font-semibold border border-red-100">
              {uploadError}
            </div>
          )}

          {/* Upload Dropzone */}
          <Card 
            className={`border-2 border-dashed transition-all duration-300 ${isDragging ? 'border-orange-500 bg-orange-50/50 scale-[1.02]' : 'border-slate-200 hover:border-orange-300 hover:bg-slate-50'}`}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
          >
            <CardContent className="p-8 flex flex-col items-center justify-center text-center space-y-4">
              <div className={`w-16 h-16 rounded-full flex items-center justify-center transition-colors ${isDragging ? 'bg-orange-100 text-orange-600' : 'bg-slate-100 text-slate-400'}`}>
                {isUploading ? <RefreshCw className="w-8 h-8 animate-spin text-orange-600" /> : <UploadCloud className="w-8 h-8" />}
              </div>
              <div>
                <p className="text-sm font-bold text-slate-800 mb-1">
                  {isUploading ? "Envoi en cours..." : "Glissez-déposez vos fichiers ici"}
                </p>
                <p className="text-xs text-slate-500 mb-4">
                  PDF, JPG, PNG jusqu'à 10MB
                </p>
                <label className={`cursor-pointer bg-orange-600 hover:bg-orange-700 text-white px-5 py-2.5 rounded-xl text-sm font-semibold shadow-sm transition-colors inline-block ${isUploading ? 'opacity-50 pointer-events-none' : ''}`}>
                  Parcourir les fichiers
                  <input 
                    type="file" 
                    className="hidden" 
                    onChange={handleFileChange}
                    ref={fileInputRef}
                    disabled={isUploading}
                    accept=".pdf,.jpg,.jpeg,.png"
                  />
                </label>
              </div>
            </CardContent>
          </Card>

          {/* Storage capacity mock */}
          <Card className="border-slate-100 shadow-sm">
            <CardContent className="p-6 space-y-4">
              <h3 className="text-sm font-bold text-slate-800">Espace de stockage sécurisé</h3>
              <div className="space-y-2">
                <div className="flex justify-between text-xs text-slate-500 font-medium">
                  <span>8.3 MB utilisés</span>
                  <span>100 MB max (Gratuit)</span>
                </div>
                <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div className="h-full bg-orange-500 w-[8%] rounded-full"></div>
                </div>
              </div>
              <button className="w-full py-2 border border-slate-200 rounded-lg text-xs font-semibold text-slate-600 hover:bg-slate-50 transition-colors">
                Passer au plan Premium
              </button>
            </CardContent>
          </Card>
        </div>

        {/* Right Col: Documents List */}
        <div className="lg:col-span-2 space-y-6">
          {/* Filters & Search */}
          <div className="flex flex-col sm:flex-row gap-4 justify-between">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="Rechercher un document (ex: Facture)..." 
                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:border-orange-500 focus:ring-1 focus:ring-orange-500 outline-none transition-all text-sm"
              />
            </div>
            <button className="flex items-center gap-2 px-4 py-2.5 border border-slate-200 rounded-xl text-sm font-semibold text-slate-600 hover:bg-slate-50 transition-colors">
              <Filter className="w-4 h-4" />
              Filtrer
            </button>
          </div>

          {/* Document Table/List */}
          <Card className="border-slate-100 shadow-sm overflow-hidden">
            <div className="bg-slate-50 border-b border-slate-100 px-6 py-3 flex items-center justify-between">
              <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Fichiers récents</span>
              <span className="text-xs text-slate-400 font-medium">{documents.length} fichiers</span>
            </div>
            <div className="divide-y divide-slate-100">
              {documents.map((doc) => (
                <div key={doc.id} className="p-4 sm:p-6 flex items-center justify-between hover:bg-slate-50/50 transition-colors group">
                  <div className="flex items-center gap-4">
                    <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${doc.type === 'pdf' ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-blue-500'}`}>
                      {doc.type === 'pdf' ? <FileText className="w-5 h-5" /> : <ImageIcon className="w-5 h-5" />}
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-slate-800 line-clamp-1">{doc.name}</h4>
                      <div className="flex items-center gap-3 mt-1 text-xs text-slate-500">
                        <span>{doc.size || formatBytes(doc.size_bytes || 0)}</span>
                        <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                        <span>{doc.date}</span>
                      </div>
                      <div className="mt-1">
                        <span className="text-[10px] text-slate-400 bg-slate-100 px-2 py-0.5 rounded-md">Liaison : {doc.relatedTo || "Non assigné"}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    {doc.status === 'validé' ? (
                      <Badge className="hidden sm:inline-flex bg-orange-50 text-orange-700 border-orange-200 hover:bg-orange-50">
                        <CheckCircle2 className="w-3 h-3 mr-1" /> Validé
                      </Badge>
                    ) : (
                      <Badge variant="outline" className="hidden sm:inline-flex text-amber-600 border-amber-200 bg-amber-50">
                        En attente
                      </Badge>
                    )}
                    
                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <a href={doc.url} target="_blank" rel="noreferrer" className="p-2 text-slate-400 hover:text-orange-600 hover:bg-orange-50 rounded-lg transition-colors" title="Ouvrir">
                        <Download className="w-4 h-4" />
                      </a>
                      <button className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Supprimer">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
              {documents.length === 0 && (
                <div className="p-8 text-center text-slate-400 text-sm">
                  Aucun document dans le coffre-fort.
                </div>
              )}
            </div>
          </Card>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import Link from "next/link"
import { Package, Shield, Truck, MapPin, BadgeCheck, AlertCircle, MessageSquare, Send } from "lucide-react"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Shipment } from "@/services/shipments"
import { TrackingMap } from "@/components/ui/tracking-map"

export default function ShipmentsClient({ initialData }: { initialData: Shipment[] }) {
  const [selectedShipmentId, setSelectedShipmentId] = useState<string | null>(
    initialData.length > 0 ? initialData[0].id : null
  )

  const selectedShipment = initialData.find((s) => s.id === selectedShipmentId)

  // Quick helper for steps
  const steps = ["navire", "port", "douane", "route", "livre"]
  const currentStepIndex = selectedShipment ? steps.indexOf(selectedShipment.status) : -1

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b border-slate-200 pb-5">
        <div>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Suivi de mes Marchandises</h1>
          <p className="text-sm text-slate-500 mt-1">
            Visualisez et pilotez le transit de vos conteneurs et lots de marchandises de bout en bout.
          </p>
        </div>
        <button 
          onClick={() => {
            alert("Pour créer un nouveau transport, il suffit de demander un devis à un transitaire ou via notre système d'appel d'offres.");
            window.location.href = '/dashboard/transitaires';
          }}
          className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2.5 rounded-xl text-sm font-semibold shadow-sm inline-flex items-center gap-2 transition-colors"
        >
          <Package className="w-4 h-4" />
          Nouveau Transport
        </button>
      </div>

      {initialData.length === 0 ? (
        <div className="text-center py-12 space-y-4">
          <div className="w-16 h-16 bg-slate-100 text-slate-400 rounded-full flex items-center justify-center mx-auto mb-4">
            <Package className="w-8 h-8" />
          </div>
          <h3 className="text-lg font-bold text-slate-800">Aucune expédition en cours</h3>
          <p className="text-sm text-slate-500 max-w-md mx-auto">
            Vous n'avez aucune expédition active pour le moment. Demandez un devis à un transitaire pour commencer.
          </p>
          <Link 
            href="/dashboard/transitaires"
            className="inline-flex bg-orange-600 hover:bg-orange-700 text-white font-semibold py-2 px-4 rounded-lg mt-4"
          >
            Trouver un transitaire
          </Link>
        </div>
      ) : (
        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left 2 Cols: Shipments Cards & Detailed Logistics Timeline */}
          <div className="lg:col-span-2 space-y-6">
            
            {/* Main Selected Shipment Card */}
            {selectedShipment && (
              <Card className="border-slate-100 shadow-sm overflow-hidden">
                {/* Header of Card */}
                <div className="bg-slate-900 text-white p-6 flex flex-col sm:flex-row justify-between gap-4">
                  <div>
                    <Badge className="bg-orange-500/10 text-orange-400 border border-orange-500/20 hover:bg-orange-500/20 text-[10px] px-2 py-0.5 font-semibold tracking-wider uppercase">
                      Dossier Actif
                    </Badge>
                    <h3 className="text-xl font-bold mt-2">{selectedShipment.title}</h3>
                    <p className="text-xs text-slate-400 mt-1">
                      {selectedShipment.origin} → {selectedShipment.destination}
                    </p>
                  </div>
                  <div className="text-left sm:text-right">
                    <p className="text-xs text-slate-400">Escrow Sécurisé</p>
                    <p className="text-lg font-bold text-orange-400">
                      {selectedShipment.escrow_amount ? `${selectedShipment.escrow_amount.toLocaleString()} FCFA` : 'Non défini'}
                    </p>
                  </div>
                </div>

                {/* Tracking Progress Bar */}
                <CardContent className="p-6 border-b border-slate-100">
                  <h4 className="text-xs text-slate-400 font-semibold uppercase tracking-wider mb-6">Progression de l'acheminement</h4>
                  
                  <div className="relative flex items-center justify-between">
                    <div className="absolute left-0 right-0 top-1/2 -translate-y-1/2 h-1 bg-slate-100 z-0"></div>
                    <div 
                      className="absolute left-0 top-1/2 -translate-y-1/2 h-1 bg-orange-500 z-0 transition-all duration-500" 
                      style={{ width: `${Math.max(0, currentStepIndex * 25)}%` }}
                    ></div>
                    
                    {/* Navigation step nodes (simplified simulation based on currentStepIndex) */}
                    {["Départ", "Port", "Douane", "Transport", "Livré"].map((step, idx) => {
                      const isCompleted = idx < currentStepIndex;
                      const isCurrent = idx === currentStepIndex;
                      
                      return (
                        <div key={idx} className="relative z-10 flex flex-col items-center">
                          {isCompleted ? (
                            <div className="w-8 h-8 rounded-full bg-orange-500 text-white flex items-center justify-center font-bold text-xs shadow-md">
                              ✓
                            </div>
                          ) : isCurrent ? (
                            <div className="w-8 h-8 rounded-full bg-white border-4 border-orange-500 text-orange-600 flex items-center justify-center font-bold text-xs shadow-md animate-pulse">
                              {idx + 1}
                            </div>
                          ) : (
                            <div className="w-8 h-8 rounded-full bg-white border-2 border-slate-200 text-slate-400 flex items-center justify-center font-bold text-xs shadow-sm">
                              {idx + 1}
                            </div>
                          )}
                          <span className={`text-xs mt-2 text-center ${isCurrent || isCompleted ? 'font-bold text-slate-800' : 'font-medium text-slate-400'}`}>
                            {step}
                          </span>
                        </div>
                      )
                    })}
                  </div>
                </CardContent>

                  {/* Quotes Received */}
                  {selectedShipment.quotes && selectedShipment.quotes.length > 0 && (
                    <CardContent className="p-6 border-b border-slate-100 bg-slate-50/50">
                      <h4 className="text-xs text-slate-400 font-semibold uppercase tracking-wider mb-4">Devis Reçus</h4>
                      <div className="space-y-3">
                        {selectedShipment.quotes.map((quote: any) => (
                          <div key={quote.id} className="flex flex-col sm:flex-row justify-between items-start sm:items-center p-4 bg-white border border-slate-200 rounded-xl hover:border-orange-200 transition-colors shadow-sm">
                            <div className="mb-3 sm:mb-0">
                              <h5 className="font-bold text-slate-800 text-sm">
                                {quote.profiles?.full_name || 'Transitaire Partenaire'}
                              </h5>
                              <p className="text-xs text-slate-500 mt-0.5">Offre pour cette expédition</p>
                              {quote.status === 'accepte' && (
                                <Badge className="mt-2 bg-orange-50 text-orange-700 border-orange-200">Offre Acceptée</Badge>
                              )}
                            </div>
                            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full sm:w-auto">
                              <div className="text-left sm:text-right">
                                <p className="font-bold text-lg text-slate-800">{quote.amount_cents ? `${quote.amount_cents.toLocaleString()} FCFA` : 'Sur demande'}</p>
                              </div>
                              {quote.status !== 'accepte' && (
                                <button 
                                  onClick={async () => {
                                    const { acceptQuote } = await import('@/app/actions/accept_quote');
                                    await acceptQuote(quote.id, selectedShipment.id);
                                    window.location.href = `/dashboard/escrow/payment?shipmentId=${selectedShipment.id}&quoteId=${quote.id}`;
                                  }}
                                  className="w-full sm:w-auto px-4 py-2 bg-slate-900 hover:bg-slate-800 text-white text-xs font-semibold rounded-lg transition-colors shadow-sm"
                                >
                                  Accepter & Payer
                                </button>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </CardContent>
                  )}

                  {/* Live GPS Tracking Map */}
                  <CardContent className="p-6 border-b border-slate-100">
                    <h4 className="text-xs text-slate-400 font-semibold uppercase tracking-wider mb-4">
                      Carte Interactive (Suivi GPS)
                    </h4>
                    <TrackingMap 
                      origin={selectedShipment.origin} 
                      destination={selectedShipment.destination} 
                      progress={selectedShipment.status === "En cours de transport" ? 65 : (selectedShipment.status === "Livré" ? 100 : 25)} 
                      temperature={selectedShipment.origin.includes("Abidjan") ? "18°C (Réfrigéré)" : "N/A"}
                    />
                  </CardContent>

                  {/* Logistics Journal Timeline (Mock for now as it needs a separate logs table) */}
                  <CardContent className="p-6 space-y-6">
                    <h4 className="text-xs text-slate-400 font-semibold uppercase tracking-wider border-b border-slate-100 pb-3">
                      Journal d'activité logistique
                    </h4>
                    <div className="relative pl-6 space-y-8 before:absolute before:left-2 before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-200">
                      <div className="text-sm text-slate-500">Mises à jour non disponibles pour cette expédition.</div>
                    </div>
                  </CardContent>

                  {/* Messagerie Interne (Chat) */}
                  <CardContent className="p-6 border-t border-slate-100 bg-slate-50/30">
                    <h4 className="text-xs text-slate-400 font-semibold uppercase tracking-wider mb-4 flex items-center gap-2">
                      <MessageSquare className="w-4 h-4" />
                      Messagerie avec le transitaire
                    </h4>
                    
                    <div className="bg-white border border-slate-200 rounded-xl overflow-hidden flex flex-col h-[300px]">
                      {/* Chat Messages */}
                      <div className="flex-1 p-4 overflow-y-auto space-y-4">
                        <div className="flex flex-col gap-1 items-end">
                          <div className="bg-orange-600 text-white p-3 rounded-2xl rounded-tr-sm text-sm max-w-[80%]">
                            Bonjour, j'ai accepté votre devis. Quand pensez-vous pouvoir enlever la marchandise ?
                          </div>
                          <span className="text-[10px] text-slate-400">10:45</span>
                        </div>
                        <div className="flex flex-col gap-1 items-start">
                          <div className="bg-slate-100 text-slate-800 p-3 rounded-2xl rounded-tl-sm text-sm max-w-[80%]">
                            Bonjour ! Merci pour votre confiance. L'enlèvement est prévu demain matin. Nous attendons juste la confirmation du paiement Escrow.
                          </div>
                          <span className="text-[10px] text-slate-400">11:02</span>
                        </div>
                      </div>
                      
                      {/* Chat Input */}
                      <div className="p-3 bg-white border-t border-slate-100 flex gap-2">
                        <input 
                          type="text" 
                          placeholder="Écrivez votre message..." 
                          className="flex-1 bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 text-sm outline-none focus:border-orange-500"
                        />
                        <button className="bg-slate-900 hover:bg-slate-800 text-white p-2 rounded-lg transition-colors">
                          <Send className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  </CardContent>
              </Card>
            )}
          </div>

          {/* Right Col: Logistics Operator Info, Docs, Actions */}
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider">Mes autres dossiers</h3>
            {initialData.map((shipment) => (
              <Card 
                key={shipment.id} 
                className={`border-slate-100 shadow-sm cursor-pointer transition-all ${selectedShipmentId === shipment.id ? 'ring-2 ring-orange-500' : 'hover:border-orange-200'}`}
                onClick={() => setSelectedShipmentId(shipment.id)}
              >
                <CardContent className="p-4 space-y-2">
                  <div className="flex justify-between items-start">
                    <h4 className="font-bold text-slate-800 text-sm">{shipment.title}</h4>
                    <Badge variant="outline" className="text-[10px]">{shipment.status}</Badge>
                  </div>
                  <p className="text-xs text-slate-500">{shipment.origin} → {shipment.destination}</p>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useTransition } from "react"
import { createGroupQuoteRequest } from "@/app/actions/quote_requests"
import { RefreshCw, AlertCircle, CheckCircle, Upload, Globe } from "lucide-react"
import Link from "next/link"

export default function GroupQuoteForm() {
  const [origin, setOrigin] = useState("Port d'Abidjan")
  const [destination, setDestination] = useState("Bamako (Guichet Unique)")
  const [cargoType, setCargoType] = useState("Général")
  const [weight, setWeight] = useState("")
  const [volume, setVolume] = useState("")
  const [description, setDescription] = useState("")
  
  const [error, setError] = useState<string | null>(null)
  const [success, setSuccess] = useState(false)
  const [isPending, startTransition] = useTransition()

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    setSuccess(false)

    if (!weight || Number(weight) <= 0) {
      setError("Veuillez renseigner un poids valide (supérieur à 0)")
      return
    }

    if (!description) {
      setError("Veuillez décrire brièvement la marchandise")
      return
    }

    startTransition(async () => {
      const res = await createGroupQuoteRequest({
        origin,
        destination,
        cargoType,
        weight: Number(weight),
        volume: Number(volume) || 0,
        description
      })

      if (res?.error) {
        setError(res.error)
      } else {
        setSuccess(true)
      }
    })
  }

  if (success) {
    return (
      <div className="p-8 text-center bg-orange-50/50 border border-orange-100 rounded-2xl space-y-6">
        <div className="w-16 h-16 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center mx-auto shadow-inner">
          <CheckCircle className="w-8 h-8" />
        </div>
        <div>
          <h4 className="text-xl font-bold text-slate-800">Demande diffusée avec succès !</h4>
          <p className="text-sm text-slate-500 max-w-md mx-auto leading-relaxed mt-2">
            Votre appel d'offres a été envoyé à tous les transitaires certifiés sur l'axe {origin} ➔ {destination}. Vous recevrez leurs devis dans votre espace.
          </p>
        </div>
        <div className="pt-4 flex justify-center gap-4">
          <Link href="/dashboard" className="px-6 py-2.5 bg-white border border-slate-200 rounded-lg text-sm font-semibold text-slate-700 hover:bg-slate-50">
            Retour au tableau de bord
          </Link>
          <Link href="/dashboard/pro" className="px-6 py-2.5 bg-slate-900 text-white rounded-lg text-sm font-semibold hover:bg-slate-800">
            Voir côté Transitaire (Démo)
          </Link>
        </div>
      </div>
    )
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {error && (
        <div className="p-4 bg-red-50 text-red-700 rounded-xl text-sm font-semibold flex items-start gap-3 border border-red-100">
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <span>{error}</span>
        </div>
      )}

      {/* Axis Information */}
      <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 space-y-6">
        <div className="flex items-center gap-2 mb-2">
          <Globe className="w-5 h-5 text-orange-600" />
          <h3 className="text-sm font-bold text-slate-800">Axe Logistique</h3>
        </div>
        <div className="grid md:grid-cols-2 gap-6">
          <div>
            <label htmlFor="origin" className="block text-xs font-semibold text-slate-500 mb-2 uppercase tracking-wider">Lieu de chargement *</label>
            <input
              type="text"
              id="origin"
              value={origin}
              onChange={(e) => setOrigin(e.target.value)}
              required
              disabled={isPending}
              className="block w-full border border-slate-200 rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
            />
          </div>
          <div>
            <label htmlFor="destination" className="block text-xs font-semibold text-slate-500 mb-2 uppercase tracking-wider">Destination Finale *</label>
            <input
              type="text"
              id="destination"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              required
              disabled={isPending}
              className="block w-full border border-slate-200 rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
            />
          </div>
        </div>
      </div>

      {/* Cargo Details */}
      <div className="space-y-6">
        <h3 className="text-sm font-bold text-slate-800 border-b border-slate-100 pb-2">Détails de la marchandise</h3>
        <div className="grid md:grid-cols-3 gap-6">
          <div>
            <label htmlFor="cargoType" className="block text-xs font-semibold text-slate-500 mb-2">Type de cargaison</label>
            <select
              id="cargoType"
              value={cargoType}
              onChange={(e) => setCargoType(e.target.value)}
              disabled={isPending}
              className="block w-full border border-slate-200 bg-white rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
            >
              <option value="Général">Général (Dry)</option>
              <option value="Frigo">Frigorifique</option>
              <option value="Véhicule">Véhicule (RORO)</option>
              <option value="Dangereux">Matières Dangereuses</option>
            </select>
          </div>
          <div>
            <label htmlFor="weight" className="block text-xs font-semibold text-slate-500 mb-2">Poids total (kg) *</label>
            <input
              type="number"
              id="weight"
              placeholder="Ex: 12000"
              value={weight}
              onChange={(e) => setWeight(e.target.value)}
              required
              disabled={isPending}
              className="block w-full border border-slate-200 rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
            />
          </div>
          <div>
            <label htmlFor="volume" className="block text-xs font-semibold text-slate-500 mb-2">Volume (m³)</label>
            <input
              type="number"
              id="volume"
              placeholder="Ex: 35"
              value={volume}
              onChange={(e) => setVolume(e.target.value)}
              disabled={isPending}
              className="block w-full border border-slate-200 rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
            />
          </div>
        </div>

        <div>
          <label htmlFor="description" className="block text-xs font-semibold text-slate-500 mb-2">Description des marchandises *</label>
          <textarea
            id="description"
            placeholder="Ex: 20 palettes de pièces automobiles détachées, non fragiles..."
            rows={4}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            disabled={isPending}
            className="block w-full border border-slate-200 rounded-lg py-3.5 px-4 text-sm text-slate-800 focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 outline-none transition-all shadow-sm"
          />
        </div>
      </div>

      {/* Bill of Lading / Invoice Upload Simulation */}
      <div className="border border-dashed border-slate-300 rounded-2xl p-6 bg-slate-50/50 flex flex-col items-center justify-center text-center">
        <div className="w-12 h-12 rounded-full bg-white border border-slate-200 flex items-center justify-center text-orange-600 mb-3 shadow-sm">
          <Upload className="w-5 h-5" />
        </div>
        <h4 className="text-sm font-bold text-slate-800 mb-1">Documents d'accompagnement</h4>
        <p className="text-xs text-slate-500 max-w-sm mb-4">
          Ajoutez une facture proforma ou un connaissement (BL) pour obtenir des devis plus précis.
        </p>
        <button type="button" className="px-5 py-2.5 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-700 hover:border-orange-300 hover:text-orange-600 transition-all shadow-sm">
          Parcourir les fichiers
        </button>
      </div>

      <button
